BEGIN IMMEDIATE;
CREATE TABLE orders_raw_restore_settlement_20260711 AS
SELECT o.rowid AS source_rowid, o.* FROM orders_raw o
JOIN bank_settlements b ON o.settlement_ref = b.settlement_ref
WHERE b.settled_on = '2026-07-11';
UPDATE orders_raw SET settlement_status = 'settled'
WHERE rowid IN (SELECT source_rowid FROM orders_raw_restore_settlement_20260711);
SELECT changes() AS updated_rows;
COMMIT;

